mapper.select:
SELECT
    o.id,type, o.order_id, o.goods_id, o.pay_price, o.service_charge,o.create_by, o.created_at, o.is_distribution,o.dept_use_id,o.whether_outbound,
    e.id as erp_order_id, e.order_sn, e.shop_id, e.shop_erp_id,e.shop_erp_name, e.shop_type, e.cat_id_1, e.cat_id_2, e.cat_id_3, e.cat_id_4,
    e.item_list, e.order_total, e.goods_amount, e.order_change_amount, e.pay_amount, e.created_at as erp_order_create_at,
    e.confirm_status, e.confirm_at, e.pay_no, e.pay_at, e.pay_type, e.platform_discount, e.buyer_memo,
    e.order_status, e.shipping_id, e.shipping_at, e.city, e.city_id, e.province, e.province_id, e.country,
    e.country_id, e.town, e.town_id, e.tracking_number, e.remark, e.remark_tag, e.remark_tag_name,
    e.receive_at, e.after_sales_status, e.updated_at, e.is_show, e.shop_md5_prefix,e.is_issue,e.erp_after_sales_status,
    e.erp_ass_create_at,e.erp_ass_reason,e.erp_ass_remark,e.erp_ass_address
FROM `order_external_goods` o
left join erp_goods_order e on e.id = o.order_id
where
    (
        o.dept_use_id = #{deptUseId}

                or  e.created_by = #{createBy}

        )


    AND e.order_sn = #{orderSn}


    AND (e.erp_after_sales_status = 0 or e.erp_after_sales_status is null)


    AND e.erp_after_sales_status != 0


    AND o.goods_id = #{goodsId}


    and e.shop_type = #{shopType}


    and o.created_at >= #{startTime}


    and o.created_at <= #{endTime}


    and o.whether_outbound = #{whetherOutbound}


    and e.order_status = #{orderStatus}

order by o.created_at desc
limit #{pageNum}, #{pageSize}

SELECT
   count(*)
FROM `order_external_goods` o
left join erp_goods_order e on e.id = o.order_id
where o.dept_use_id = #{deptUseId}

    AND e.order_sn = #{orderSn}


    AND (e.erp_after_sales_status = 0 or e.erp_after_sales_status is null)


    AND e.erp_after_sales_status != 0


    AND o.goods_id = #{goodsId}


    and e.shop_type = #{shopType}


    and o.created_at >= #{startTime}


    and o.created_at <= #{endTime}


    and o.whether_outbound = #{whetherOutbound}



    and id = #{id}
    and type = #{type},
    and order_id = #{orderId}
    and goods_id = #{goodsId}
    and pay_price = #{payPrice}
    and service_charge = #{serviceCharge}
    and create_by = #{createBy}
    and created_at = #{createdAt}
    and is_distribution = #{isDistribution}

order by created_at desc

mapper.insert:
insert into order_external_goods (
type, order_id, goods_id, pay_price, service_charge, create_by, created_at, is_distribution, dept_use_id, whether_outbound,
) values (
#{type}, #{orderId}, #{goodsId}, #{payPrice}, #{serviceCharge}, #{createBy}, #{createdAt}, #{isDistribution}, #{deptUseId}, #{whetherOutbound},
)

mapper.update:
update order_external_goods
type = #{type}, order_id = #{orderId}, goods_id = #{goodsId}, pay_price = #{payPrice}, service_charge = #{serviceCharge}, create_by = #{createBy}, created_at = #{createdAt}, is_distribution = #{isDistribution}, dept_use_id = #{deptUseId} whether_outbound = #{whetherOutbound},
where id = #{id}
